CREATE TABLE `TowerDefenseCharacter` (
	`id` varchar(191) NOT NULL,
	`name` varchar(191) NOT NULL,
	`isPlayer` boolean NOT NULL DEFAULT false,
	`baseHealth` int NOT NULL DEFAULT 10,
	`baseSpeed` double NOT NULL DEFAULT 0.4,
	`baseDamage` int NOT NULL DEFAULT 10,
	`attackCooldown` double NOT NULL DEFAULT 1,
	`healthScaling` double NOT NULL DEFAULT 0.15,
	`speedScaling` double NOT NULL DEFAULT 0.02,
	`damageScaling` double NOT NULL DEFAULT 2,
	`firstAppearWave` int NOT NULL DEFAULT 1,
	`baseCount` int NOT NULL DEFAULT 3,
	`countScaling` double NOT NULL DEFAULT 1.5,
	`scaleFactor` double NOT NULL DEFAULT 2.8,
	`assetConfig` json DEFAULT ('null'),
	`createdAt` datetime(3) NOT NULL DEFAULT (CURRENT_TIMESTAMP(3)),
	`updatedAt` datetime(3) NOT NULL DEFAULT (CURRENT_TIMESTAMP(3)),
	CONSTRAINT `TowerDefenseCharacter_id` PRIMARY KEY(`id`)
);

CREATE TABLE `TowerDefenseRun` (
	`id` varchar(191) NOT NULL,
	`seed` varchar(191) NOT NULL,
	`userId` varchar(191) NOT NULL,
	`startedAt` datetime(3) NOT NULL DEFAULT (CURRENT_TIMESTAMP(3)),
	`endedAt` datetime(3),
	`wave` int NOT NULL DEFAULT 0,
	`score` int NOT NULL DEFAULT 0,
	`gridSize` int NOT NULL DEFAULT 5,
	`status` enum('ACTIVE','COMPLETED','ABANDONED') NOT NULL DEFAULT 'ACTIVE',
	`state` json NOT NULL,
	CONSTRAINT `TowerDefenseRun_id` PRIMARY KEY(`id`)
);

CREATE TABLE `TowerDefenseUpgrade` (
	`id` varchar(191) NOT NULL,
	`name` varchar(191) NOT NULL,
	`description` text NOT NULL,
	`maxLevel` int NOT NULL DEFAULT 10,
	`baseCost` int NOT NULL DEFAULT 100,
	`costMultiplier` double NOT NULL DEFAULT 1.5,
	`upgradeType` enum('DAMAGE','ATTACK_SPEED','RANGE','CRIT_CHANCE','DAMAGE_PER_TILE','HEALTH','HEALTH_REGEN','DEFENSE_PERCENT','DEFENSE_FLAT','LIFESTEAL','KNOCKBACK_CHANCE','KNOCKBACK_FORCE','TOKENS_PER_WAVE','TOKENS_PER_KILL','INTEREST_PER_WAVE','SKIP_ENEMY_CHANCE','ABILITY_UNLOCK') NOT NULL,
	`effectValue` double NOT NULL DEFAULT 0.1,
	`createdAt` datetime(3) NOT NULL DEFAULT (CURRENT_TIMESTAMP(3)),
	`updatedAt` datetime(3) NOT NULL DEFAULT (CURRENT_TIMESTAMP(3)),
	CONSTRAINT `TowerDefenseUpgrade_id` PRIMARY KEY(`id`)
);

CREATE TABLE `UserTowerDefenseUpgrade` (
	`id` varchar(191) NOT NULL,
	`userId` varchar(191) NOT NULL,
	`upgradeId` varchar(191) NOT NULL,
	`level` int NOT NULL DEFAULT 1,
	`purchasedAt` datetime(3) NOT NULL DEFAULT (CURRENT_TIMESTAMP(3)),
	CONSTRAINT `UserTowerDefenseUpgrade_id` PRIMARY KEY(`id`),
	CONSTRAINT `UserTowerDefenseUpgrade_userId_upgradeId_key` UNIQUE(`userId`,`upgradeId`)
);

ALTER TABLE `UserData` ADD `towerDefensePoints` int DEFAULT 0 NOT NULL;
CREATE INDEX `TowerDefenseCharacter_name_idx` ON `TowerDefenseCharacter` (`name`);
CREATE INDEX `TowerDefenseCharacter_firstAppearWave_idx` ON `TowerDefenseCharacter` (`firstAppearWave`);
CREATE INDEX `TowerDefenseCharacter_isPlayer_idx` ON `TowerDefenseCharacter` (`isPlayer`);
CREATE INDEX `TowerDefenseRun_userId_idx` ON `TowerDefenseRun` (`userId`);
CREATE INDEX `TowerDefenseRun_status_idx` ON `TowerDefenseRun` (`status`);
CREATE INDEX `TowerDefenseRun_userId_status_idx` ON `TowerDefenseRun` (`userId`,`status`);
CREATE INDEX `TowerDefenseRun_score_idx` ON `TowerDefenseRun` (`score`);
CREATE INDEX `TowerDefenseRun_startedAt_idx` ON `TowerDefenseRun` (`startedAt`);
CREATE INDEX `TowerDefenseUpgrade_name_idx` ON `TowerDefenseUpgrade` (`name`);
CREATE INDEX `TowerDefenseUpgrade_upgradeType_idx` ON `TowerDefenseUpgrade` (`upgradeType`);
CREATE INDEX `UserTowerDefenseUpgrade_userId_idx` ON `UserTowerDefenseUpgrade` (`userId`);
CREATE INDEX `UserTowerDefenseUpgrade_upgradeId_idx` ON `UserTowerDefenseUpgrade` (`upgradeId`);


-- Seed Tower Defense Upgrades (sorted by simplicity within each category)
INSERT INTO `TowerDefenseUpgrade` (`id`, `name`, `description`, `image`, `maxLevel`, `baseCost`, `costMultiplier`, `upgradeType`, `effectValue`) VALUES
-- Attack Upgrades (simple to complex: damage, speed, range, crit, longshot)
('td-damage', 'Damage', 'Increase base damage of all attacks', '/towerdefence/upgrades/damage.png', 10, 10, 1.5, 'DAMAGE', 0.1),
('td-attack-speed', 'Attack Speed', 'Reduce cooldown between attacks', '/towerdefence/upgrades/attack-speed.png', 10, 10, 1.5, 'ATTACK_SPEED', 0.1),
('td-range', 'Range', 'Increase attack range', '/towerdefence/upgrades/range.png', 5, 15, 2.0, 'RANGE', 1),
('td-crit-chance', 'Critical Strike', 'Chance to deal double damage', '/towerdefence/upgrades/crit.png', 10, 15, 1.5, 'CRIT_CHANCE', 0.05),
('td-damage-per-tile', 'Long Shot', 'Deal extra damage based on projectile distance', '/towerdefence/upgrades/longshot.png', 5, 20, 2.0, 'DAMAGE_PER_TILE', 2),
-- Defense Upgrades (simple to complex: health, flat defense, % defense, regen, lifesteal, knockback)
('td-health', 'Max Health', 'Increase maximum health', '/towerdefence/upgrades/health.png', 10, 10, 1.5, 'HEALTH', 0.1),
('td-defense-flat', 'Toughness', 'Reduce incoming damage by a flat amount', '/towerdefence/upgrades/toughness.png', 10, 10, 1.5, 'DEFENSE_FLAT', 2),
('td-defense-percent', 'Armor', 'Reduce incoming damage by a percentage', '/towerdefence/upgrades/armor.png', 10, 15, 1.8, 'DEFENSE_PERCENT', 0.05),
('td-health-regen', 'Health Regen', 'Regenerate health over time', '/towerdefence/upgrades/regen.png', 10, 15, 1.6, 'HEALTH_REGEN', 0.01),
('td-lifesteal', 'Life Steal', 'Recover health based on damage dealt', '/towerdefence/upgrades/lifesteal.png', 10, 20, 1.6, 'LIFESTEAL', 0.02),
('td-knockback-chance', 'Knockback', 'Chance to push enemies back on hit', '/towerdefence/upgrades/knockback.png', 10, 15, 1.5, 'KNOCKBACK_CHANCE', 0.05),
('td-knockback-force', 'Repelling Force', 'Increase how far enemies are knocked back', '/towerdefence/upgrades/force.png', 5, 20, 2.0, 'KNOCKBACK_FORCE', 0.5),
-- Utility Upgrades (simple to complex: tokens per kill, tokens per wave, interest, skip enemy)
('td-tokens-per-kill', 'Bounty Hunter', 'Earn more tokens per enemy killed', '/towerdefence/upgrades/bounty.png', 10, 15, 1.5, 'TOKENS_PER_KILL', 2),
('td-tokens-per-wave', 'Wave Bonus', 'Gain bonus tokens at the start of each wave', '/towerdefence/upgrades/wave-bonus.png', 10, 10, 1.4, 'TOKENS_PER_WAVE', 5),
('td-interest', 'Interest', 'Earn interest on your tokens at wave end', '/towerdefence/upgrades/interest.png', 10, 20, 1.7, 'INTEREST_PER_WAVE', 0.02),
('td-skip-enemy', 'Intimidation', 'Chance for enemies to not spawn', '/towerdefence/upgrades/intimidate.png', 10, 25, 1.8, 'SKIP_ENEMY_CHANCE', 0.02);

